3	import (
4		"fmt"
5		"time"
6	)
7	
8	// MigrateStats reports what Migrate did in a single pass.
9	type MigrateStats struct {
10		// EventsExternalized is the number of beads whose inline events were
11		// moved to the .ddx/attachments/<id>/events.jsonl sidecar.
12		EventsExternalized int
13		// Archived is the number of closed beads moved from the active
14		// collection to beads-archive.
15		Archived int
16	}
17	
18	// Changed reports whether Migrate mutated on-disk state in this pass.
19	func (m MigrateStats) Changed() bool {
20		return m.EventsExternalized > 0 || m.Archived > 0
21	}
22	
23	// Migrate splits the existing active beads collection into the modern
24	// layout: closed beads' inline events are externalized to the attachment
25	// store (per ADR-004), and eligible closed beads are moved to the
26	// beads-archive partner (per TD-027). It is idempotent — a second call
27	// with no further changes is a no-op.
28	//
29	// Migrate uses a permissive archival policy (MinAge=0, MinActiveCount=0)
30	// so it drains the historical backlog. Routine archival (after Close)
31	// continues to use DefaultArchivePolicy.
32	func (s *Store) Migrate() (MigrateStats, error) {
33		return s.ArchiveWithEvents(migratePolicy())
34	}
35	
36	// MigrateDryRun reports what Migrate would do without mutating disk. It uses
37	// the same eligibility logic as Migrate (Statuses=[closed], no MinAge floor,
38	// preserve_dependencies retention).
39	func (s *Store) MigrateDryRun() (MigrateStats, error) {
40		var stats MigrateStats
41		if s.Collection != DefaultCollection {
42			return stats, fmt.Errorf("bead: migrate dry-run only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
43		}
44		policy := migratePolicy()
45	
46		var beads []Bead
47		err := s.WithLock(func() error {
48			all, _, rerr := s.readAllLatestRaw()
49			if rerr != nil {
50				return rerr
51			}
52			beads = all
53			return nil
54		})
55		if err != nil {
56			return stats, err
57		}
58	
59		referenced := make(map[string]bool)
60		for _, b := range beads {
61			if b.Status == StatusClosed {
62				continue
63			}
64			for _, dep := range b.DepIDs() {
65				referenced[dep] = true
66			}
67		}
68	
69		for _, b := range beads {
70			if !containsString(policy.Statuses, b.Status) {
71				continue
72			}
73			if hasInlineEvents(&b) {
74				stats.EventsExternalized++
75			}
76			if referenced[b.ID] {
77				continue
78			}
79			ts := b.UpdatedAt
80			if raw, ok := b.Extra["closed_at"].(string); ok {
81				if parsed, perr := time.Parse(time.RFC3339, raw); perr == nil {
82					ts = parsed
83				}
84			}
85			if policy.MinAge > 0 && time.Now().UTC().Sub(ts) < policy.MinAge {
86				continue
87			}
88			stats.Archived++
89		}
90		return stats, nil
91	}
92	
93	func migratePolicy() ArchivePolicy {
94		return ArchivePolicy{
95			Statuses:       []string{StatusClosed},
96			MinAge:         0,
97			MinActiveCount: 0,
98			BatchSize:      0,
99		}
100	}
101	
102	// ArchiveWithEvents externalizes inline events for every bead whose status
103	// matches policy.Statuses, then archives eligible beads under the same
104	// policy. This is the operator-facing path used by `ddx bead archive` and
105	// the internal path used by `ddx bead migrate`.
106	func (s *Store) ArchiveWithEvents(policy ArchivePolicy) (MigrateStats, error) {
107		var stats MigrateStats
108		if s.Collection != DefaultCollection {
109			return stats, fmt.Errorf("bead: archive only runs from the active %q collection (got %q)", DefaultCollection, s.Collection)
110		}
111	
112		// Step 1: externalize inline events on every eligible-status bead under
113		// the active store's lock. This shrinks the row size before we try to
114		// archive, so the archive partner inherits already-thin rows.
115		err := s.WithLock(func() error {
116			beads, _, rerr := s.readAllLatestRaw()
117			if rerr != nil {
118				return rerr
119			}
120			dirty := false
121			for i := range beads {
122				if !containsString(policy.Statuses, beads[i].Status) {
123					continue
124				}
125				if !hasInlineEvents(&beads[i]) {
126					continue
127				}
128				if eerr := s.externalizeEventsInPlace(&beads[i]); eerr != nil {
129					return eerr
130				}
131				stats.EventsExternalized++
132				dirty = true
133			}
134			if !dirty {
135				return nil
136			}
137			return s.WriteAll(beads)
138		})
139		if err != nil {
140			return stats, fmt.Errorf("bead: archive externalize: %w", err)
141		}
142	
143		moved, err := s.Archive(policy)
144		if err != nil {
145			return stats, fmt.Errorf("bead: archive: %w", err)
146		}
147		stats.Archived = len(moved)
148		return stats, nil
149	}
150	
151	// hasInlineEvents reports whether a bead carries any inline events that
152	// can still be externalized. An empty array counts as "no inline events"
153	// so a second migrate pass on an already-externalized bead is a no-op.
154	func hasInlineEvents(b *Bead) bool {
155		if b == nil || b.Extra == nil {
156			return false
157		}
158		raw, ok := b.Extra["events"]
159		if !ok {
160			return false
161		}
162		return len(decodeBeadEvents(raw)) > 0
163	}
