230	// beadWithoutInlineEvents returns a shallow copy of b whose Extra map omits
231	// the "events" key. The original Extra map is not mutated so callers can
232	// continue using the in-memory bead value after the split.
233	func beadWithoutInlineEvents(b Bead) Bead {
234		if b.Extra == nil {
235			return b
236		}
237		if _, ok := b.Extra["events"]; !ok {
238			return b
239		}
240		cp := make(map[string]any, len(b.Extra))
241		for k, v := range b.Extra {
242			if k == "events" {
243				continue
244			}
245			cp[k] = v
246		}
247		b.Extra = cp
248		return b
249	}
250	
251	// axonEncodeBead writes a bead in axon's row shape:
252	//
253	//	{ "_collection": "ddx_beads", "schema_version": 1, "data": {<bead JSON>} }
254	//
255	// The wrapper carries the collection name and schema version that a future
256	// genqlient-driven implementation needs; the data field is the same bead
257	// JSON the JSONL backend writes, so import/export round-trip continues to
258	// share marshalBead.
259	func axonEncodeBead(b Bead) ([]byte, error) {
260		data, err := marshalBead(b)
261		if err != nil {
262			return nil, err
263		}
264		var raw json.RawMessage = data
265		envelope := axonEntityEnvelope{
266			Collection:    AxonBeadsCollection,
267			SchemaVersion: axonSchemaVersion,
268			Data:          raw,
269		}
270		return json.Marshal(envelope)
271	}
272	
273	// axonEncodeEvent writes one event entity in the ddx_bead_events
274	// collection. The event_of field is the link target back to the parent bead
275	// (per TD-030 D3); index gives a deterministic position so re-reads preserve
276	// insertion order even when on-disk shuffling occurs.
277	func axonEncodeEvent(beadID string, index int, ev BeadEvent) ([]byte, error) {
278		row := axonEventEnvelope{
279			Collection:    AxonEventsCollection,
280			SchemaVersion: axonSchemaVersion,
281			EventOf:       beadID,
282			Index:         index,
283			Event:         ev,
284		}
285		return json.Marshal(row)
286	}
