288	type axonEntityEnvelope struct {
289		Collection    string          `json:"_collection"`
290		SchemaVersion int             `json:"schema_version"`
291		Data          json.RawMessage `json:"data"`
292	}
293	
294	type axonEventEnvelope struct {
295		Collection    string    `json:"_collection"`
296		SchemaVersion int       `json:"schema_version"`
297		EventOf       string    `json:"event_of"`
298		Index         int       `json:"index"`
299		Event         BeadEvent `json:"event"`
300	}
