337	type axonEventRecord struct {
338		beadID string
339		index  int
340		event  BeadEvent
341	}
342	
343	func (a *AxonBackend) readEventEntities() ([]axonEventRecord, error) {
344		data, err := os.ReadFile(a.EventsFile)
345		if os.IsNotExist(err) {
346			return nil, nil
347		}
348		if err != nil {
349			return nil, fmt.Errorf("bead: axon read %s: %w", a.EventsFile, err)
350		}
351		scanner := bufio.NewScanner(bytes.NewReader(data))
352		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
353		var out []axonEventRecord
354		for scanner.Scan() {
355			line := bytes.TrimSpace(scanner.Bytes())
356			if len(line) == 0 {
357				continue
358			}
359			var env axonEventEnvelope
360			if err := json.Unmarshal(line, &env); err != nil {
361				return nil, fmt.Errorf("bead: axon parse event row: %w", err)
362			}
363			if env.Collection != AxonEventsCollection || env.EventOf == "" {
364				continue
365			}
366			out = append(out, axonEventRecord{
367				beadID: env.EventOf,
368				index:  env.Index,
369				event:  env.Event,
370			})
371		}
372		if err := scanner.Err(); err != nil {
373			return nil, fmt.Errorf("bead: axon scan events: %w", err)
374		}
375		// Stable sort within each bead so insertion order is recoverable on read
376		// regardless of how WriteAll batched lines into the file.
377		sort.SliceStable(out, func(i, j int) bool {
378			if out[i].beadID != out[j].beadID {
379				return out[i].beadID < out[j].beadID
380			}
381			return out[i].index < out[j].index
382		})
383		return out, nil
384	}
