13	// Import reads beads from an external source and merges them into the store.
14	// Returns the number of beads imported.
15	func (s *Store) Import(source, filePath string) (int, error) {
16		if source == "" || source == "auto" {
17			return s.importAuto(filePath)
18		}
19	
20		switch source {
21		case "bd":
22			return s.importFromTool("bd")
23		case "br":
24			return s.importFromTool("br")
25		case "jsonl":
