32	// ExportTo writes all beads as JSONL to the given writer.
33	//
34	// For interchange compatibility with bd/br, externalized event histories are
35	// inlined back into the row's "events" array on the way out (the attachment
36	// ref itself is also dropped so importers don't see a dangling pointer).
37	// The on-disk row is unchanged — this is a transient mutation on the copied
38	// Bead value before marshaling.
39	//
40	// When called on the active collection, archived beads from the
41	// beads-archive partner are also streamed inline so a single export carries
42	// the full corpus. Each archived bead's externalized events are loaded from
43	// the active store's attachment dir (where Migrate writes them) before
44	// emission.
45	func (s *Store) ExportTo(w io.Writer) error {
46		beads, err := s.ReadAll()
47		if err != nil {
48			return err
49		}
50		seen := make(map[string]bool, len(beads))
51		for _, b := range beads {
52			seen[b.ID] = true
53			if hasEventsAttachment(&b) {
54				if err := s.inlineEventsInPlace(&b); err != nil {
55					return fmt.Errorf("bead: export inline events: %w", err)
56				}
57			}
58			data, err := marshalBead(b)
59			if err != nil {
60				return fmt.Errorf("bead: export marshal: %w", err)
61			}
62			if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
63				return fmt.Errorf("bead: export write: %w", err)
64			}
65		}
66	
67		if s.Collection != DefaultCollection {
68			return nil
69		}
70		archive := s.archivePartner()
71		archived, aerr := archive.ReadAll()
72		if aerr != nil {
73			// Treat a missing/unreadable archive partner as empty — the
74			// active collection is still a valid export.
75			return nil
76		}
77		for _, b := range archived {
78			if seen[b.ID] {
79				continue
80			}
81			if hasEventsAttachment(&b) {
82				// Attachments live under the active store's .ddx/attachments
83				// dir even after the bead moves to the archive (Migrate
84				// writes them there before archival). Use s, not archive,
85				// to resolve the sidecar path.
86				if err := s.inlineEventsInPlace(&b); err != nil {
87					return fmt.Errorf("bead: export inline events: %w", err)
88				}
89			}
90			data, err := marshalBead(b)
91			if err != nil {
92				return fmt.Errorf("bead: export marshal: %w", err)
93			}
94			if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
95				return fmt.Errorf("bead: export write: %w", err)
96			}
97		}
98		return nil
99	}
