136	func (s *Store) importAuto(filePath string) (int, error) {
137		// Try bd
138		if _, err := exec.LookPath("bd"); err == nil {
139			n, err := s.importFromTool("bd")
140			if err == nil && n > 0 {
141				return n, nil
142			}
143		}
144	
145		// Try br
146		if _, err := exec.LookPath("br"); err == nil {
147			n, err := s.importFromTool("br")
148			if err == nil && n > 0 {
149				return n, nil
150			}
151		}
152	
153		// Try known bead file locations in priority order
154		beadsFile := filePath
155		if beadsFile == "" {
156			for _, candidate := range []string{
157				".beads/issues.jsonl", // bd default
158				".helix/issues.jsonl", // HELIX legacy tracker
159			} {
160				if _, err := os.Stat(candidate); err == nil {
161					beadsFile = candidate
162					break
163				}
164			}
165			if beadsFile == "" {
166				beadsFile = ".beads/issues.jsonl" // fallback for error message
167			}
168		}
169		return s.importFromJSONL(beadsFile)
170	}
