190	func (s *Store) mergeJSONL(data string) (int, error) {
191		var incoming []Bead
192		var parseErrors int
193	
194		// Try as JSON array first, then as JSONL
195		trimmed := strings.TrimSpace(data)
196		if strings.HasPrefix(trimmed, "[") {
197			var raw []json.RawMessage
198			if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
199				return 0, fmt.Errorf("bead: import parse: %w", err)
200			}
201			for _, r := range raw {
202				b, err := unmarshalBead(r)
203				if err != nil {
204					parseErrors++
205					continue
206				}
207				incoming = append(incoming, b)
208			}
209		} else {
210			for _, line := range strings.Split(trimmed, "\n") {
211				line = strings.TrimSpace(line)
212				if line == "" {
213					continue
214				}
215				b, err := unmarshalBead([]byte(line))
216				if err != nil {
217					parseErrors++
218					continue
219				}
220				incoming = append(incoming, b)
221			}
222		}
223	
224		if parseErrors > 0 && len(incoming) == 0 {
225			return 0, fmt.Errorf("bead: import failed: %d malformed record(s), 0 valid", parseErrors)
226		}
227		if parseErrors > 0 {
228			fmt.Fprintf(os.Stderr, "bead: import: skipped %d malformed record(s)\n", parseErrors)
229		}
230	
231		if len(incoming) == 0 {
232			return 0, nil
233		}
234	
235		return s.mergeBeads(incoming)
236	}
237	
238	func (s *Store) mergeBeads(incoming []Bead) (int, error) {
239		var count int
240		err := s.WithLock(func() error {
241			existing, err := s.ReadAll()
242			if err != nil {
243				return err
244			}
245	
246			existingIDs := make(map[string]bool)
247			for _, b := range existing {
248				existingIDs[b.ID] = true
249			}
250	
251			// Collect IDs from incoming for cross-reference validation
252			incomingIDs := make(map[string]bool)
253			for _, b := range incoming {
254				incomingIDs[b.ID] = true
255			}
256	
257			for _, b := range incoming {
258				if existingIDs[b.ID] {
259					continue // skip duplicates
260				}
261				// Normalize: ensure valid status
262				if b.Status != StatusOpen && b.Status != StatusInProgress && b.Status != StatusClosed {
263					b.Status = StatusOpen
264				}
265				// Clamp priority
266				if b.Priority < MinPriority {
267					b.Priority = MinPriority
268				}
269				if b.Priority > MaxPriority {
270					b.Priority = MaxPriority
271				}
272				// Validate deps exist in either existing or incoming set
273				for _, depID := range b.DepIDs() {
274					if !existingIDs[depID] && !incomingIDs[depID] {
275						fmt.Fprintf(os.Stderr, "bead: import: %s has dangling dep %s (skipped)\n", b.ID, depID)
276					}
277				}
278				existing = append(existing, b)
279				existingIDs[b.ID] = true
280				count++
281			}
282	
283			// Validate no circular dependencies in merged set
284			depMap := make(map[string][]string)
285			for _, b := range existing {
286				depMap[b.ID] = b.DepIDs()
287			}
288			for _, b := range existing {
289				if len(b.Dependencies) > 0 && hasCycle(depMap, b.ID) {
290					return fmt.Errorf("bead: import would create circular dependency involving %s", b.ID)
291				}
292			}
293	
294			return s.WriteAll(existing)
295		})
296		return count, err
297	}
