11	// JSONLBackend stores beads as newline-delimited JSON in a single file under
12	// a .ddx directory. It is the storage shape used by Store's built-in path and
13	// is also the fallback ExternalBackend reaches for when bd/br cannot serve a
14	// non-default collection (e.g. "beads-archive"). Constructed directly only
15	// when a RawBackend value is needed standalone — Store's inline path predates
16	// this type and continues to operate on the same file format.
17	type JSONLBackend struct {
18		Dir      string
19		File     string
20		LockDir  string
21		LockWait time.Duration
22	}
23	
24	// NewJSONLBackend constructs a JSONL-backed Backend rooted at dir. file and
25	// lockDir must be absolute (or rooted under dir) and are written/locked
26	// directly. lockWait bounds how long WithLock spins before giving up.
27	// Compile-time check: JSONLBackend satisfies RawBackend.
28	var _ RawBackend = (*JSONLBackend)(nil)
29	
30	func NewJSONLBackend(dir, file, lockDir string, lockWait time.Duration) *JSONLBackend {
31		return &JSONLBackend{Dir: dir, File: file, LockDir: lockDir, LockWait: lockWait}
32	}
33	
34	func (j *JSONLBackend) Init() error {
35		if err := os.MkdirAll(j.Dir, 0o755); err != nil {
36			return fmt.Errorf("bead: init dir: %w", err)
37		}
38		f, err := os.OpenFile(j.File, os.O_CREATE|os.O_WRONLY, 0o644)
39		if err != nil {
40			return fmt.Errorf("bead: init file: %w", err)
41		}
42		return f.Close()
43	}
44	
45	func (j *JSONLBackend) ReadAll() ([]Bead, error) {
46		data, err := os.ReadFile(j.File)
47		if os.IsNotExist(err) {
48			return nil, nil
49		}
50		if err != nil {
51			return nil, fmt.Errorf("bead: read %s: %w", j.File, err)
52		}
53		beads, _, err := parseBeadJSONL(data)
54		if err != nil {
55			return nil, fmt.Errorf("bead: parse %s: %w", j.File, err)
56		}
57		return foldLatestBeads(beads), nil
58	}
59	
60	func (j *JSONLBackend) WriteAll(beads []Bead) error {
61		sort.Slice(beads, func(a, b int) bool { return beads[a].ID < beads[b].ID })
62		if err := os.MkdirAll(j.Dir, 0o755); err != nil {
63			return fmt.Errorf("bead: mkdir: %w", err)
64		}
65		var buf []byte
66		for _, b := range beads {
67			data, err := marshalBead(b)
68			if err != nil {
69				return fmt.Errorf("bead: marshal: %w", err)
70			}
71			buf = append(buf, data...)
72			buf = append(buf, '\n')
73		}
74		return writeAtomicFile(j.File, buf)
75	}
76	
77	func (j *JSONLBackend) WithLock(fn func() error) error {
78		wait := j.LockWait
79		if wait <= 0 {
80			wait = 10 * time.Second
81		}
82		if err := acquireDirLock(j.Dir, j.LockDir, wait); err != nil {
83			return err
84		}
85		defer os.RemoveAll(j.LockDir)
86		return fn()
87	}
