89	// jsonlFallbackForCollection builds a JSONLBackend for the given collection
90	// rooted at ddxDir, using the default registry's spec to resolve file/lock
91	// paths. Used by the external backend when bd/br cannot serve a non-default
92	// collection through their CLI surface.
93	func jsonlFallbackForCollection(ddxDir, collection string, lockWait time.Duration) *JSONLBackend {
94		spec := DefaultRegistry().Resolve(CollectionID(collection))
95		file, lockDir := spec.PathsUnder(ddxDir)
96		// Defensive — Resolve should always return non-empty names, but guard
97		// against an empty CollectionID by computing a conventional pair.
98		if file == ddxDir || lockDir == ddxDir {
99			file = filepath.Join(ddxDir, collection+".jsonl")
100			lockDir = filepath.Join(ddxDir, collection+".lock")
101		}
102		return NewJSONLBackend(ddxDir, file, lockDir, lockWait)
103	}
