14	// EventsAttachmentExtraKey is the Extra map key under which a closed/archived
15	// bead records the path to its externalized events.jsonl sidecar. Per ADR-004
16	// §"Attachment Model", attachment references live in preserved extras and
17	// must not shadow bd/br envelope fields. The value is a path relative to
18	// `<.ddx-dir>/attachments/`, e.g. "ddx-abcdef12/events.jsonl".
19	const EventsAttachmentExtraKey = "events_attachment"
20	
21	// EventsAttachmentFileName is the conventional sidecar filename for
22	// externalized events.
23	const EventsAttachmentFileName = "events.jsonl"
24	
25	// attachmentDir returns the absolute directory under .ddx/attachments/ that
26	// owns this bead's sidecars.
27	func (s *Store) attachmentDir(beadID string) string {
28		return filepath.Join(s.Dir, "attachments", beadID)
29	}
30	
31	// eventsAttachmentPath returns the absolute path to a bead's events.jsonl
32	// sidecar.
33	func (s *Store) eventsAttachmentPath(beadID string) string {
34		return filepath.Join(s.attachmentDir(beadID), EventsAttachmentFileName)
35	}
36	
37	// eventsAttachmentRelPath returns the path stored in Extra[events_attachment]:
38	// it's relative to .ddx/attachments/ and uses forward slashes regardless of
39	// platform so the value round-trips through bd/br interchange unchanged.
40	func eventsAttachmentRelPath(beadID string) string {
41		return beadID + "/" + EventsAttachmentFileName
42	}
43	
44	// hasEventsAttachment reports whether the bead carries an externalized events
45	// sidecar reference.
46	func hasEventsAttachment(b *Bead) bool {
47		if b == nil || b.Extra == nil {
48			return false
49		}
50		v, ok := b.Extra[EventsAttachmentExtraKey].(string)
51		return ok && strings.TrimSpace(v) != ""
52	}
53	
54	// readEventsAttachment loads a bead's externalized events from disk. Missing
55	// file is treated as an empty event log so a half-written close does not
56	// crash the read path; it returns ([]BeadEvent{}, nil) in that case.
57	func (s *Store) readEventsAttachment(beadID string) ([]BeadEvent, error) {
58		path := s.eventsAttachmentPath(beadID)
59		data, err := os.ReadFile(path)
60		if os.IsNotExist(err) {
61			return []BeadEvent{}, nil
62		}
63		if err != nil {
64			return nil, fmt.Errorf("bead: read events attachment %s: %w", path, err)
65		}
66		scanner := bufio.NewScanner(bytes.NewReader(data))
67		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
68		var out []BeadEvent
69		for scanner.Scan() {
70			line := bytes.TrimSpace(scanner.Bytes())
71			if len(line) == 0 {
72				continue
73			}
74			var m map[string]any
75			if err := json.Unmarshal(line, &m); err != nil {
76				return nil, fmt.Errorf("bead: parse events attachment %s: %w", path, err)
77			}
78			out = append(out, beadEventFromMap(m))
79		}
80		if err := scanner.Err(); err != nil {
81			return nil, fmt.Errorf("bead: scan events attachment %s: %w", path, err)
82		}
83		if out == nil {
84			out = []BeadEvent{}
85		}
86		return out, nil
87	}
88	
89	// writeEventsAttachment writes the given events to the bead's sidecar file
90	// atomically (temp + rename) and creates the parent directory. An empty
91	// slice removes the sidecar.
92	func (s *Store) writeEventsAttachment(beadID string, events []BeadEvent) error {
93		dir := s.attachmentDir(beadID)
94		path := s.eventsAttachmentPath(beadID)
95		if len(events) == 0 {
96			_ = os.Remove(path)
97			return nil
98		}
99		if err := os.MkdirAll(dir, 0o755); err != nil {
100			return fmt.Errorf("bead: mkdir attachments: %w", err)
101		}
102		var buf bytes.Buffer
103		enc := json.NewEncoder(&buf)
104		enc.SetEscapeHTML(false)
105		for _, e := range events {
106			row := map[string]any{
107				"kind":       e.Kind,
108				"summary":    e.Summary,
109				"body":       e.Body,
110				"actor":      e.Actor,
111				"created_at": e.CreatedAt.UTC().Format(time.RFC3339Nano),
112				"source":     e.Source,
113			}
114			if err := enc.Encode(row); err != nil {
115				return fmt.Errorf("bead: encode events attachment: %w", err)
116			}
117		}
118		return writeAtomicFile(path, buf.Bytes())
119	}
120	
121	// eventsForBead returns the bead's events from whichever physical store
122	// currently holds them: the inline Extra["events"] array, or the externalized
123	// sidecar referenced by Extra[events_attachment]. When both are present the
124	// sidecar wins, matching the externalize-then-clear ordering used by Close.
125	func (s *Store) eventsForBead(b *Bead) ([]BeadEvent, error) {
126		if b == nil {
127			return nil, nil
128		}
129		if hasEventsAttachment(b) {
130			return s.readEventsAttachment(b.ID)
131		}
132		if b.Extra == nil {
133			return nil, nil
134		}
135		if raw, ok := b.Extra["events"]; ok {
136			return decodeBeadEvents(raw), nil
137		}
138		return nil, nil
139	}
